"use client";

import {
  ToolUIErrorBoundary,
  type ToolUIErrorBoundaryProps,
} from "@/components/tool-ui/shared";

export function StatsDisplayErrorBoundary(
  props: Omit<ToolUIErrorBoundaryProps, "componentName">,
) {
  const { children, ...rest } = props;
  return (
    <ToolUIErrorBoundary componentName="StatsDisplay" {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );
}

export { StatsDisplay } from "./stats-display";
export { StatsDisplayErrorBoundary } from "./error-boundary";
export { Sparkline, type SparklineProps } from "./sparkline";
export {
  SerializableStatsDisplaySchema,
  parseSerializableStatsDisplay,
  StatFormatSchema,
  StatDiffSchema,
  StatSparklineSchema,
  StatItemSchema,
  type SerializableStatsDisplay,
  type StatsDisplayProps,
  type StatFormat,
  type StatDiff,
  type StatSparkline,
  type StatItem,
} from "./schema";

import { z } from "zod";
import { ToolUIIdSchema, ToolUIRoleSchema, parseWithSchema } from "@/components/tool-ui/shared";

const TextFormatSchema = z.object({
  kind: z.literal("text"),
});

const NumberFormatSchema = z.object({
  kind: z.literal("number"),
  decimals: z.number().int().min(0).optional(),
  compact: z.boolean().optional(),
});

const CurrencyFormatSchema = z.object({
  kind: z.literal("currency"),
  currency: z.string().min(1),
  decimals: z.number().int().min(0).optional(),
});

const PercentFormatSchema = z.object({
  kind: z.literal("percent"),
  decimals: z.number().int().min(0).optional(),
  basis: z.enum(["fraction", "unit"]).optional(),
});

export const StatFormatSchema = z.discriminatedUnion("kind", [
  TextFormatSchema,
  NumberFormatSchema,
  CurrencyFormatSchema,
  PercentFormatSchema,
]);

export type StatFormat = z.infer<typeof StatFormatSchema>;

export const StatDiffSchema = z.object({
  value: z.number(),
  decimals: z.number().int().min(0).optional(),
  upIsPositive: z.boolean().optional(),
  label: z.string().optional(),
});

export type StatDiff = z.infer<typeof StatDiffSchema>;

export const StatSparklineSchema = z.object({
  data: z.array(z.number()).min(2),
  color: z.string().optional(),
});

export type StatSparkline = z.infer<typeof StatSparklineSchema>;

export const StatItemSchema = z.object({
  key: z.string().min(1),
  label: z.string().min(1),
  value: z.union([z.string(), z.number()]),
  format: StatFormatSchema.optional(),
  diff: StatDiffSchema.optional(),
  sparkline: StatSparklineSchema.optional(),
});

export type StatItem = z.infer<typeof StatItemSchema>;

export const SerializableStatsDisplaySchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  title: z.string().optional(),
  description: z.string().optional(),
  stats: z.array(StatItemSchema).min(1),
});

export type SerializableStatsDisplay = z.infer<
  typeof SerializableStatsDisplaySchema
>;

export function parseSerializableStatsDisplay(
  input: unknown,
): SerializableStatsDisplay {
  return parseWithSchema(SerializableStatsDisplaySchema, input, "StatsDisplay");
}

export interface StatsDisplayProps extends SerializableStatsDisplay {
  className?: string;
  locale?: string;
}

"use client";

import type { CSSProperties } from "react";
import { useId } from "react";
import { cn } from "./_adapter";

export interface SparklineProps {
  data: number[];
  color?: string;
  width?: number;
  height?: number;
  className?: string;
  style?: CSSProperties;
  showFill?: boolean;
  fillOpacity?: number;
}

export function Sparkline({
  data,
  color = "currentColor",
  width = 64,
  height = 24,
  className,
  style,
  showFill = false,
  fillOpacity = 0.09,
}: SparklineProps) {
  const gradientId = useId();

  if (data.length < 2) {
    return null;
  }

  const minVal = Math.min(...data);
  const maxVal = Math.max(...data);
  const range = maxVal - minVal || 1;

  const padding = 0;
  const usableWidth = width;
  const usableHeight = height;

  const linePoints = data.map((value, index) => {
    const x = padding + (index / (data.length - 1)) * usableWidth;
    const y = padding + usableHeight - ((value - minVal) / range) * usableHeight;
    return { x, y };
  });

  const linePointsString = linePoints.map((p) => `${p.x},${p.y}`).join(" ");

  const areaPointsString = [
    `${padding},${height}`,
    ...linePoints.map((p) => `${p.x},${p.y}`),
    `${width - padding},${height}`,
  ].join(" ");

  const animationDelay = style?.animationDelay ?? "0ms";

  return (
    <svg
      viewBox={`0 0 ${width} ${height}`}
      aria-hidden="true"
      className={cn("h-full w-full shrink-0", className)}
      style={style}
      preserveAspectRatio="none"
    >
      {showFill && (
        <>
          <defs>
            <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={color} stopOpacity={fillOpacity} />
              <stop offset="100%" stopColor={color} stopOpacity={0} />
            </linearGradient>
          </defs>
          <polygon
            points={areaPointsString}
            fill={`url(#${gradientId})`}
            className="animate-in fade-in duration-1000 ease-[cubic-bezier(0.16,1,0.3,1)] fill-mode-both"
            style={{ animationDelay }}
          />
        </>
      )}
      <polyline
        points={linePointsString}
        fill="none"
        stroke={color}
        strokeWidth={1}
        strokeOpacity={0.15}
        strokeLinecap="round"
        strokeLinejoin="round"
        vectorEffect="non-scaling-stroke"
      />
      <polyline
        points={linePointsString}
        fill="none"
        stroke={color}
        strokeWidth={0.75}
        strokeLinecap="round"
        strokeLinejoin="round"
        vectorEffect="non-scaling-stroke"
        pathLength={1}
        strokeDasharray="0.36 0.64"
        strokeDashoffset={1}
        strokeOpacity={0}
        className="animate-[sparkline-glint-slow_0.8s_ease-out_forwards]"
        style={{ animationDelay }}
      />
      <polyline
        points={linePointsString}
        fill="none"
        stroke={color}
        strokeWidth={0.75}
        strokeLinecap="round"
        strokeLinejoin="round"
        vectorEffect="non-scaling-stroke"
        pathLength={1}
        strokeDasharray="0.24 0.76"
        strokeDashoffset={1}
        strokeOpacity={0}
        className="animate-[sparkline-glint_0.8s_ease-out_forwards]"
        style={{ animationDelay }}
      />
      <style>{`
        @keyframes sparkline-glint {
          0% { stroke-dashoffset: 1; stroke-opacity: 0; }
          20% { stroke-opacity: 0.9; }
          100% { stroke-dashoffset: -1; stroke-opacity: 0; }
        }
        @keyframes sparkline-glint-slow {
          0% { stroke-dashoffset: 1; stroke-opacity: 0; }
          20% { stroke-opacity: 0.2; }
          100% { stroke-dashoffset: -1; stroke-opacity: 0; }
        }
      `}</style>
    </svg>
  );
}

"use client";
import {
  cn,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
} from "./_adapter";
import type { StatsDisplayProps, StatItem, StatFormat, StatDiff } from "./schema";
import { Sparkline } from "./sparkline";

interface FormattedValueProps {
  value: string | number;
  format?: StatFormat;
  locale?: string;
}

function FormattedValue({ value, format, locale }: FormattedValueProps) {
  if (typeof value === "string" || !format) {
    return <span className="font-light tabular-nums">{String(value)}</span>;
  }

  switch (format.kind) {
    case "number": {
      const decimals = format.decimals ?? 0;
      if (format.compact) {
        const parts = new Intl.NumberFormat(locale, {
          minimumFractionDigits: decimals,
          maximumFractionDigits: decimals,
          notation: "compact",
        }).formatToParts(value);
        const fullNumber = new Intl.NumberFormat(locale).format(value);
        return (
          <span className="font-light tabular-nums" aria-label={fullNumber}>
            {parts.map((part, i) =>
              part.type === "compact" ? (
                <span key={i} className="ml-0.5 text-[0.65em] opacity-80" aria-hidden="true">{part.value}</span>
              ) : (
                <span key={i}>{part.value}</span>
              )
            )}
          </span>
        );
      }
      const formatted = new Intl.NumberFormat(locale, {
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
      }).format(value);
      return <span className="font-light tabular-nums">{formatted}</span>;
    }
    case "currency": {
      const currency = format.currency;
      const decimals = format.decimals ?? 2;
      const formatted = new Intl.NumberFormat(locale, {
        style: "currency",
        currency,
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
      }).format(value);
      const spokenValue = new Intl.NumberFormat(locale, {
        style: "currency",
        currency,
        currencyDisplay: "name",
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
      }).format(value);
      return <span className="font-light tabular-nums" aria-label={spokenValue}>{formatted}</span>;
    }
    case "percent": {
      const decimals = format.decimals ?? 2;
      const basis = format.basis ?? "fraction";
      const numeric = basis === "fraction" ? value * 100 : value;
      const formatted = numeric.toFixed(decimals);
      return (
        <span className="font-light tabular-nums" aria-label={`${formatted} percent`}>
          {formatted}
          <span className="ml-0.5 text-[0.65em] opacity-80" aria-hidden="true">%</span>
        </span>
      );
    }
    case "text":
    default:
      return <span className="font-light tabular-nums">{String(value)}</span>;
  }
}

interface DeltaValueProps {
  diff: StatDiff;
}

function DeltaValue({ diff }: DeltaValueProps) {
  const { value, decimals = 1, upIsPositive = true, label } = diff;

  const isPositive = value > 0;
  const isNegative = value < 0;

  const isGood = upIsPositive ? isPositive : isNegative;
  const isBad = upIsPositive ? isNegative : isPositive;

  const colorClass = isGood
    ? "text-green-600 dark:text-green-500"
    : isBad
      ? "text-red-600 dark:text-red-500"
      : "text-muted-foreground";

  const bgClass = isGood
    ? "bg-green-500/10 dark:bg-green-500/15"
    : isBad
      ? "bg-red-500/10 dark:bg-red-500/15"
      : "bg-muted";

  const formatted = Math.abs(value).toFixed(decimals);
  const sign = isNegative ? "−" : "+";
  const display = `${sign}${formatted}%`;

  return (
    <span className={cn("inline-flex items-center gap-1 rounded-full px-1.5 py-0.5 text-xs font-semibold tabular-nums", colorClass, bgClass)}>
      {!upIsPositive && <span className="text-[0.9em]">{isGood ? "↓" : "↑"}</span>}
      {display}
      {label && <span className="text-muted-foreground font-normal">{label}</span>}
    </span>
  );
}

interface StatCardProps {
  stat: StatItem;
  locale?: string;
  isSingle?: boolean;
  index?: number;
}

function StatCard({ stat, locale, isSingle = false, index = 0 }: StatCardProps) {
  const sparklineColor = stat.sparkline?.color ?? "var(--muted-foreground)";
  const hasSparkline = Boolean(stat.sparkline);
  const baseDelay = index * 175;

  return (
    <div
      className={cn(
        "relative flex min-h-28 flex-col gap-1 px-6",
        isSingle ? "justify-center" : "justify-end"
      )}
    >
      {hasSparkline && (
        <Sparkline
          data={stat.sparkline!.data}
          color={sparklineColor}
          showFill
          fillOpacity={0.09}
          className="pointer-events-none absolute inset-x-0 top-2 bottom-2 animate-in fade-in slide-in-from-bottom-12 duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] fill-mode-both"
          style={{ animationDelay: `${baseDelay}ms` }}
        />
      )}
      <span
        className="text-muted-foreground relative text-xs font-normal tracking-wider uppercase opacity-90 animate-in fade-in slide-in-from-bottom-1 duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] fill-mode-both"
        style={{ animationDelay: `${baseDelay + 75}ms` }}
      >
        {stat.label}
      </span>
      <div
        className="relative flex items-baseline gap-2 pb-2 animate-in fade-in slide-in-from-bottom-2 duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] fill-mode-both"
        style={{ animationDelay: `${baseDelay + 150}ms` }}
      >
        <span className={cn(
          "font-light tracking-normal",
          isSingle ? "text-5xl" : "text-3xl"
        )}>
          <FormattedValue
            value={stat.value}
            format={stat.format}
            locale={locale}
          />
        </span>
        {stat.diff && <DeltaValue diff={stat.diff} />}
      </div>
    </div>
  );
}

export function StatsDisplay({
  id,
  title,
  description,
  stats,
  className,
  locale: localeProp,
}: StatsDisplayProps) {
  const locale = localeProp ?? (typeof navigator !== "undefined" ? navigator.language : undefined);
  const hasHeader = Boolean(title || description);
  const isSingle = stats.length === 1;

  return (
    <article
      data-slot="stats-display"
      data-tool-ui-id={id}
      className={cn(
        "w-full min-w-80 max-w-xl",
        isSingle && "max-w-sm",
        className
      )}
    >
      <Card className={cn("overflow-clip !pb-0 !pt-2", hasHeader && "!gap-0")}>
        {hasHeader && (
          <CardHeader className="border-b border-border !pt-3 !pb-4">
            {title && <CardTitle className="text-pretty">{title}</CardTitle>}
            {description && (
              <CardDescription className="text-pretty">
                {description}
              </CardDescription>
            )}
          </CardHeader>
        )}
        <CardContent className="@container overflow-hidden p-0">
          <div
            className="grid @[440px]:-ml-px @[440px]:-mt-px"
            style={{
              gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
            }}
          >
            {stats.map((stat, index) => (
              <div
                key={stat.key}
                className={cn(
                  "overflow-clip py-3 first:pt-0 @[440px]:py-3 @[440px]:first:pt-3 @[440px]:border-l @[440px]:border-t @[440px]:border-border",
                  index > 0 && "border-border border-t"
                )}
              >
                <StatCard stat={stat} locale={locale} isSingle={isSingle} index={index} />
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </article>
  );
}
